import{_ as a,c as i,o as l,ae as s}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"KiwiPanel Coding Standards","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/kiwi_panel_coding_standards.md","filePath":"advanced/kiwi_panel_coding_standards.md"}'),t={name:"advanced/kiwi_panel_coding_standards.md"};function r(o,e,n,d,c,h){return l(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="kiwipanel-coding-standards" tabindex="-1">KiwiPanel Coding Standards <a class="header-anchor" href="#kiwipanel-coding-standards" aria-label="Permalink to &quot;KiwiPanel Coding Standards&quot;">​</a></h1><blockquote><p><strong>Status:</strong> Canonical</p><p>This document defines mandatory coding, security, and operational standards for all KiwiPanel scripts, installers, and system components.</p></blockquote><hr><h2 id="_1-core-principles" tabindex="-1">1. Core Principles <a class="header-anchor" href="#_1-core-principles" aria-label="Permalink to &quot;1. Core Principles&quot;">​</a></h2><p>KiwiPanel code MUST be:</p><ol><li><strong>Deterministic</strong> – Same input, same result</li><li><strong>Non-interactive</strong> – No prompts in production paths</li><li><strong>Idempotent</strong> – Safe to re-run multiple times</li><li><strong>OS-native</strong> – Follow distro conventions, not personal preference</li><li><strong>Transparent</strong> – No hidden behavior, no silent failures</li><li><strong>Secure by default</strong> – Least privilege, secrets never exposed</li></ol><hr><h2 id="_2-supported-platforms" tabindex="-1">2. Supported Platforms <a class="header-anchor" href="#_2-supported-platforms" aria-label="Permalink to &quot;2. Supported Platforms&quot;">​</a></h2><p>All KiwiPanel shell code MUST support:</p><ul><li>Debian (stable)</li><li>Ubuntu LTS</li><li>RHEL / Rocky Linux / AlmaLinux</li></ul><p>Unsupported platforms MUST fail fast with a clear error.</p><hr><h2 id="_3-shell-requirements" tabindex="-1">3. Shell Requirements <a class="header-anchor" href="#_3-shell-requirements" aria-label="Permalink to &quot;3. Shell Requirements&quot;">​</a></h2><h3 id="_3-1-interpreter-safety-flags" tabindex="-1">3.1 Interpreter &amp; Safety Flags <a class="header-anchor" href="#_3-1-interpreter-safety-flags" aria-label="Permalink to &quot;3.1 Interpreter &amp; Safety Flags&quot;">​</a></h3><p>All shell scripts MUST start with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -euo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipefail</span></span></code></pre></div><p>Do NOT disable these flags.</p><hr><h3 id="_3-2-bash-version" tabindex="-1">3.2 Bash Version <a class="header-anchor" href="#_3-2-bash-version" aria-label="Permalink to &quot;3.2 Bash Version&quot;">​</a></h3><ul><li>Target: <strong>bash ≥ 4.2</strong></li><li>Avoid bashisms that break older enterprise systems</li></ul><hr><h2 id="_4-logging-standards" tabindex="-1">4. Logging Standards <a class="header-anchor" href="#_4-logging-standards" aria-label="Permalink to &quot;4. Logging Standards&quot;">​</a></h2><h3 id="_4-1-mandatory-logging-helpers" tabindex="-1">4.1 Mandatory Logging Helpers <a class="header-anchor" href="#_4-1-mandatory-logging-helpers" aria-label="Permalink to &quot;4.1 Mandatory Logging Helpers&quot;">​</a></h3><p>Scripts MUST define and use:</p><ul><li><code>log_info</code></li><li><code>log_warn</code></li><li><code>log_error</code></li><li><code>log_success</code></li></ul><p>Rules:</p><ul><li>Every major step MUST log</li><li>Errors MUST be actionable</li><li>No silent failures</li></ul><hr><h3 id="_4-2-log-files" tabindex="-1">4.2 Log Files <a class="header-anchor" href="#_4-2-log-files" aria-label="Permalink to &quot;4.2 Log Files&quot;">​</a></h3><ul><li>Global installer log: <code>/var/log/kiwipanel-install.log</code></li><li>Service logs: <strong>OS-native paths only</strong></li></ul><p>Examples:</p><ul><li>Debian/Ubuntu: <code>/var/log/mysql/error.log</code></li><li>RHEL-family: <code>/var/log/mariadb/mariadb.log</code></li></ul><p>Never invent custom log locations.</p><hr><h2 id="_5-os-service-detection" tabindex="-1">5. OS &amp; Service Detection <a class="header-anchor" href="#_5-os-service-detection" aria-label="Permalink to &quot;5. OS &amp; Service Detection&quot;">​</a></h2><h3 id="_5-1-os-detection" tabindex="-1">5.1 OS Detection <a class="header-anchor" href="#_5-1-os-detection" aria-label="Permalink to &quot;5.1 OS Detection&quot;">​</a></h3><ul><li>Use <code>/etc/os-release</code></li><li>Map to logical families (<code>debian</code>, <code>rhel</code>)</li><li>Fail fast on unsupported OS</li></ul><hr><h3 id="_5-2-systemd-rules" tabindex="-1">5.2 systemd Rules <a class="header-anchor" href="#_5-2-systemd-rules" aria-label="Permalink to &quot;5.2 systemd Rules&quot;">​</a></h3><ul><li>Always run <code>systemctl daemon-reload</code> after installs</li><li>Detect service name dynamically (<code>mariadb</code> vs <code>mysql</code>)</li><li>Never assume service names</li></ul><hr><h2 id="_6-package-management" tabindex="-1">6. Package Management <a class="header-anchor" href="#_6-package-management" aria-label="Permalink to &quot;6. Package Management&quot;">​</a></h2><h3 id="_6-1-repository-policy" tabindex="-1">6.1 Repository Policy <a class="header-anchor" href="#_6-1-repository-policy" aria-label="Permalink to &quot;6.1 Repository Policy&quot;">​</a></h3><ul><li><strong>LTS-only</strong> packages</li><li>Official upstream repositories only</li><li>Third-party repos MUST be justified</li></ul><h3 id="_6-2-non-interactive-installs" tabindex="-1">6.2 Non-interactive Installs <a class="header-anchor" href="#_6-2-non-interactive-installs" aria-label="Permalink to &quot;6.2 Non-interactive Installs&quot;">​</a></h3><ul><li>Debian/Ubuntu: <code>DEBIAN_FRONTEND=noninteractive</code></li><li>RHEL-family: <code>dnf</code> preferred, <code>yum</code> fallback</li></ul><hr><h2 id="_7-configuration-management" tabindex="-1">7. Configuration Management <a class="header-anchor" href="#_7-configuration-management" aria-label="Permalink to &quot;7. Configuration Management&quot;">​</a></h2><h3 id="_7-1-single-source-of-truth" tabindex="-1">7.1 Single Source of Truth <a class="header-anchor" href="#_7-1-single-source-of-truth" aria-label="Permalink to &quot;7.1 Single Source of Truth&quot;">​</a></h3><ul><li>Policy variables MUST be defined once</li><li>No duplicated defaults</li><li>Generated files MUST be clearly marked</li></ul><hr><h3 id="_7-2-file-permissions" tabindex="-1">7.2 File Permissions <a class="header-anchor" href="#_7-2-file-permissions" aria-label="Permalink to &quot;7.2 File Permissions&quot;">​</a></h3><p>Mandatory rules:</p><ul><li>Secrets: <code>600</code></li><li>Config directories: <code>755</code></li><li>Secrets directory: <code>700</code></li></ul><p>Never weaken permissions.</p><hr><h2 id="_8-secrets-handling-critical" tabindex="-1">8. Secrets Handling (CRITICAL) <a class="header-anchor" href="#_8-secrets-handling-critical" aria-label="Permalink to &quot;8. Secrets Handling (CRITICAL)&quot;">​</a></h2><h3 id="_8-1-storage" tabindex="-1">8.1 Storage <a class="header-anchor" href="#_8-1-storage" aria-label="Permalink to &quot;8.1 Storage&quot;">​</a></h3><ul><li>All secrets MUST be stored in <code>/etc/kiwipanel/secrets.env</code></li><li>Secrets MUST be shell-escaped</li></ul><p>Required format:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">value</span></span></code></pre></div><p>Implementation:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%s=%q\\n&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><hr><h3 id="_8-2-display-rules-non-negotiable" tabindex="-1">8.2 Display Rules (NON-NEGOTIABLE) <a class="header-anchor" href="#_8-2-display-rules-non-negotiable" aria-label="Permalink to &quot;8.2 Display Rules (NON-NEGOTIABLE)&quot;">​</a></h3><p>❌ NEVER:</p><ul><li>Echo passwords</li><li>Print secrets to terminal</li><li>Log credentials</li></ul><p>✅ Allowed:</p><ul><li>Indicate where secrets are stored</li><li>Provide retrieval instructions</li></ul><hr><h2 id="_9-database-standards-mariadb" tabindex="-1">9. Database Standards (MariaDB) <a class="header-anchor" href="#_9-database-standards-mariadb" aria-label="Permalink to &quot;9. Database Standards (MariaDB)&quot;">​</a></h2><ul><li>LTS versions only</li><li>Root remote access disabled</li><li>No anonymous users</li><li>No test database</li><li>Socket authentication preferred</li></ul><p>Idempotency is mandatory for:</p><ul><li>Users</li><li>Databases</li><li>Privileges</li></ul><hr><h2 id="_10-portability-rules" tabindex="-1">10. Portability Rules <a class="header-anchor" href="#_10-portability-rules" aria-label="Permalink to &quot;10. Portability Rules&quot;">​</a></h2><h3 id="_10-1-forbidden-commands" tabindex="-1">10.1 Forbidden Commands <a class="header-anchor" href="#_10-1-forbidden-commands" aria-label="Permalink to &quot;10.1 Forbidden Commands&quot;">​</a></h3><p>Avoid:</p><ul><li><code>grep -P</code> / <code>grep -oP</code></li><li>GNU-only flags when POSIX alternatives exist</li></ul><p>Prefer:</p><ul><li><code>sed</code></li><li><code>awk</code></li><li>POSIX-compatible tools</li></ul><hr><h2 id="_11-error-handling" tabindex="-1">11. Error Handling <a class="header-anchor" href="#_11-error-handling" aria-label="Permalink to &quot;11. Error Handling&quot;">​</a></h2><ul><li>Fail fast on unrecoverable errors</li><li>Retry only when meaningful</li><li>Always show logs on service failures</li></ul><p>Never swallow errors with <code>|| true</code> unless justified and documented.</p><hr><h2 id="_12-health-checks" tabindex="-1">12. Health Checks <a class="header-anchor" href="#_12-health-checks" aria-label="Permalink to &quot;12. Health Checks&quot;">​</a></h2><p>Every installer MUST provide:</p><ul><li>Service status check</li><li>Socket connection test</li><li>Version verification</li><li>Disk space sanity check</li></ul><p>Health checks MUST fail the installer if critical components are broken.</p><hr><h2 id="_13-output-ux" tabindex="-1">13. Output &amp; UX <a class="header-anchor" href="#_13-output-ux" aria-label="Permalink to &quot;13. Output &amp; UX&quot;">​</a></h2><ul><li>Output MUST be readable in SSH</li><li>No emojis in production output</li><li>Clear section separators allowed</li><li>Final summary MUST state success or failure clearly</li></ul><hr><h2 id="_14-versioning-metadata" tabindex="-1">14. Versioning &amp; Metadata <a class="header-anchor" href="#_14-versioning-metadata" aria-label="Permalink to &quot;14. Versioning &amp; Metadata&quot;">​</a></h2><p>Scripts MUST include:</p><ul><li>Name</li><li>Purpose</li><li>Version</li><li>Supported OS</li><li>Policy notes</li></ul><p>Semantic versioning is recommended.</p><hr><h2 id="_15-what-kiwipanel-code-is-not" tabindex="-1">15. What KiwiPanel Code Is NOT <a class="header-anchor" href="#_15-what-kiwipanel-code-is-not" aria-label="Permalink to &quot;15. What KiwiPanel Code Is NOT&quot;">​</a></h2><p>KiwiPanel code is NOT:</p><ul><li>Interactive wizards</li><li>Black-box installers</li><li>Magic scripts</li><li>&quot;Works on my machine&quot; hacks</li></ul><hr><h2 id="_16-enforcement" tabindex="-1">16. Enforcement <a class="header-anchor" href="#_16-enforcement" aria-label="Permalink to &quot;16. Enforcement&quot;">​</a></h2><ul><li>Code not following this standard MUST NOT be merged</li><li>Security violations are immediate blockers</li><li>Convenience never overrides correctness</li></ul><hr><p><strong>KiwiPanel philosophy:</strong></p><blockquote><p><em>If it’s not predictable, secure, and debuggable — it doesn’t ship.</em></p></blockquote>`,108)])])}const g=a(t,[["render",r]]);export{u as __pageData,g as default};
